  "findings": [
    {
      "dimension": "philosophy_depth",
      "score": 6,
      "finding": "The six principles are catchy but remain high-level slogans without actionable, fundraising-specific tactics or metrics.",
      "example_rewrite": "| Principle                | Meaning                                                     |\n|--------------------------|-------------------------------------------------------------|\n| **Data-Driven Narrative**| Use slide-view analytics and investor Q&A patterns to refine your story each week. |"
    },
    {
      "dimension": "handoff_specificity",
      "score": 6,
      "finding": "The receive/deliver tables use vague roles like “All Teams” and omit specific artifacts such as a cap table or technical specs.",
      "example_rewrite": "| Receives From       | Artifact                     |\n|---------------------|------------------------------|\n| CFO                 | Fundraising targets & strategy document |\n| Financial Controller| Updated cap table (.xlsx)   |\n| Product Team        | MVP technical spec sheet     |\n| Marketing Team      | Last 30-day user acquisition metrics |\n\n| Delivers To         | Artifact                     |\n|---------------------|------------------------------|\n| CEO                 | Finalized pitch deck (PDF)   |\n| CFO                 | Weekly pipeline status report (*.pptx) |\n| Legal               | Draft term sheet (.docx)     |"
    },
    {
      "dimension": "anti_pattern_quality",
      "score": 1,
      "finding": "No anti-patterns section is provided. The role needs 3–5 fundraising-specific pitfalls to warn against.",
      "example_rewrite": "## Anti-Patterns\n- **Data Dumping**: Overloading the data room with untagged or irrelevant files, slowing due diligence.\n- **Ghosting Investors**: Failing to respond within 24 hours to serious investor inquiries.\n- **One-Size-Fits-All Decks**: Sending the same pitch to diverse investors without tailoring terms or market focus.\n- **Skipping Founder Prep**: Entering meetings without aligning founders on messaging and Q&A roles."
    }
  ],
  "top_improvement": "Add a dedicated Anti-Patterns section with 3–5 fundraising-specific pitfalls to guide users away from common mistakes."
}
